mapper.update:
/*updateInsurance*/
	UPDATE INSURANCE_CONTRACT
	SET CTT_NM		= #{cttNm}
		,CTT_USER		= #{cttUser}
		,STATS			= #{stats}
		,CTT_START_DATE = #{cttStartDate}
		,PAY_PEOD		= #{payPeod}
		,TNSF_DATE	= #{tnsfDate}
		,INS_AMT		= #{insAmt}
		,BANK				= #{bank}
		,TMNT_DATE	= #{tmntDate}
		,ETC				= #{etc}
		,MANAGER		= #{manager}
		,PHONE_NUM	= #{phoneNum}
		,ATCH_FILE_ID	= #{atchFileId}
		,UPD_DATE		= SYSDATE
	WHERE INS_CPY = #{insCpy}
	AND CTFC_NUM = #{ctfcNum}

mapper.delete:
/*deleteInsurance*/
	DELETE FROM INSURANCE_CONTRACT A
	WHERE A.INS_CPY = #{insCpy}
	AND A.CTFC_NUM = #{ctfcNum}
